-- Setup: catalog and schema for BI-facing views (run by catalog admin)
CREATE CATALOG IF NOT EXISTS analytics;
CREATE SCHEMA  IF NOT EXISTS analytics.gold;

-- BI-facing view with business column naming over internal gold table
CREATE OR REPLACE VIEW analytics.gold.v_sales_daily AS
SELECT
  report_date                AS date,
  region,
  product_category           AS category,
  channel                    AS sales_channel,
  total_revenue,
  order_count,
  unique_customers
FROM main.gold.sales_daily;  -- internal catalog.schema.table

-- Row-level security view: users see only their region; admins see all
CREATE OR REPLACE VIEW analytics.gold.v_sales_regional AS
SELECT *
FROM main.gold.sales_daily
WHERE region = SESSION_CONTEXT('region')
   OR IS_ACCOUNT_GROUP_MEMBER('data_admin');

-- Grant hierarchy for BI service principal (Power BI / Tableau service account)
GRANT USE CATALOG ON CATALOG analytics                    TO `bi-service-principal`;
GRANT USE SCHEMA  ON SCHEMA  analytics.gold               TO `bi-service-principal`;
GRANT SELECT      ON VIEW    analytics.gold.v_sales_daily TO `bi-service-principal`;

-- Grant to AD group for analyst users
GRANT USE CATALOG ON CATALOG analytics                        TO `tableau-users`;
GRANT USE SCHEMA  ON SCHEMA  analytics.gold                   TO `tableau-users`;
GRANT SELECT      ON VIEW    analytics.gold.v_sales_daily     TO `tableau-users`;
GRANT SELECT      ON VIEW    analytics.gold.v_sales_regional  TO `tableau-users`;

-- Unity Catalog row filter function (transparent to BI; applied at table level)
CREATE FUNCTION IF NOT EXISTS main.security.region_filter(region_col STRING)
  RETURN IS_ACCOUNT_GROUP_MEMBER('data_admin') OR region_col = SESSION_CONTEXT('region');

ALTER TABLE main.gold.sales_daily
  SET ROW FILTER main.security.region_filter ON (region);

-- Column mask: hide customer PII from non-admin users
CREATE FUNCTION IF NOT EXISTS main.security.mask_customer_id(customer_id STRING)
  RETURN CASE WHEN IS_ACCOUNT_GROUP_MEMBER('data_admin') THEN customer_id
              ELSE regexp_replace(customer_id, '.', '*') END;

ALTER TABLE main.gold.fact_orders
  ALTER COLUMN customer_id SET MASK main.security.mask_customer_id;

-- Audit: verify what is granted on a view
SHOW GRANTS ON VIEW analytics.gold.v_sales_daily;
SHOW GRANTS ON TABLE main.gold.sales_daily;

-- Dry run: list files that would be deleted without committing
VACUUM silver.orders DRY RUN;

-- Standard VACUUM (uses table retentionDuration property or 7-day default)
VACUUM silver.orders;

-- VACUUM with explicit retention override for this run
VACUUM silver.orders RETAIN 240 HOURS;  -- 10 days

-- Set persistent table-level retention (30 days for audited tables)
ALTER TABLE gold.dim_customer
SET TBLPROPERTIES ('delta.deletedFileRetentionDuration' = 'interval 30 days');

-- Verify time travel still works after VACUUM (must be within retained window)
SELECT COUNT(*) FROM silver.orders VERSION AS OF 10;

-- Show current table properties including retentionDuration
SHOW TBLPROPERTIES silver.orders;

-- Override minimum retention check (DEV/TEST only -- NEVER in production)
-- spark.conf.set('spark.databricks.delta.retentionDurationCheck.enabled', 'false')
-- VACUUM silver.events RETAIN 0 HOURS  -- deletes all unreferenced files immediately

-- NOT NULL at table creation
CREATE TABLE IF NOT EXISTS silver.orders (
  order_id    STRING        NOT NULL,
  customer_id STRING        NOT NULL,
  amount      DECIMAL(18,2),
  status      STRING        NOT NULL,
  order_ts    TIMESTAMP     NOT NULL,
  order_date  DATE          NOT NULL
)
USING DELTA
PARTITIONED BY (order_date);

-- Pre-validate before adding CHECK constraint (zero violations required)
SELECT COUNT(*) AS violations FROM silver.orders WHERE NOT (amount > 0);
SELECT COUNT(*) AS violations FROM silver.orders
WHERE status NOT IN ('pending','active','shipped','cancelled','refunded');

-- Add CHECK constraints
ALTER TABLE silver.orders
ADD CONSTRAINT orders_amount_positive CHECK (amount > 0);

ALTER TABLE silver.orders
ADD CONSTRAINT orders_status_valid
CHECK (status IN ('pending','active','shipped','cancelled','refunded'));

ALTER TABLE silver.orders
ADD CONSTRAINT orders_date_matches_ts CHECK (order_date = CAST(order_ts AS DATE));

-- Drop a constraint
ALTER TABLE silver.orders DROP CONSTRAINT orders_date_matches_ts;

-- View all constraints (stored as delta.constraints.<name> in TBLPROPERTIES)
SHOW TBLPROPERTIES silver.orders;

-- Informational PK and FK (Unity Catalog; NOT enforced at write time)
CREATE TABLE IF NOT EXISTS gold.dim_customer (
  customer_sk BIGINT GENERATED ALWAYS AS IDENTITY,
  customer_id STRING NOT NULL,
  region      STRING,
  CONSTRAINT pk_dim_customer PRIMARY KEY (customer_sk)
) USING DELTA;

CREATE TABLE IF NOT EXISTS gold.fact_orders (
  order_id    STRING        NOT NULL,
  customer_sk BIGINT        NOT NULL,
  amount      DECIMAL(18,2),
  report_date DATE,
  CONSTRAINT pk_fact_orders PRIMARY KEY (order_id),
  CONSTRAINT fk_customer    FOREIGN KEY (customer_sk)
    REFERENCES gold.dim_customer(customer_sk)  -- informational only; not enforced
) USING DELTA PARTITIONED BY (report_date);

