import dlt
from pyspark.sql.functions import col, current_timestamp

# --- Python: Streaming table (Auto Loader source) ---
@dlt.table(
    name='orders_bronze',
    comment='Raw orders ingested from landing zone',
    table_properties={'delta.enableChangeDataFeed': 'true'}
)
def orders_bronze():
    return (
        spark.readStream
        .format('cloudFiles')
        .option('cloudFiles.format', 'json')
        .option('cloudFiles.schemaLocation',
                f"{dlt.read('_dlt_meta').inputFiles[0]}")  # or hardcoded path
        .load('/mnt/landing/orders/')
        .withColumn('_ingested_at', current_timestamp())
    )

# --- Python: Streaming table (upstream DLT table source) ---
@dlt.table(name='orders_silver')
def orders_silver():
    return (
        dlt.read_stream('orders_bronze')           # streaming read of upstream DLT table
        .filter(col('order_id').isNotNull())
        .select('order_id', 'customer_id', 'amount', 'status', '_ingested_at')
    )

# --- Python: Materialized view (full recomputation each update) ---
@dlt.table(name='daily_order_summary')
def daily_order_summary():
    return (
        dlt.read('orders_silver')                  # batch (non-streaming) read
        .groupBy('order_date', 'region')
        .agg({'amount': 'sum', 'order_id': 'count'})
    )

# --- Python: Temporary view (not persisted as Delta table) ---
@dlt.view(name='filtered_orders_view')
def filtered_orders_view():
    return dlt.read('orders_silver').filter(col('status') == 'active')

