# --- @dlt.expect: warn and track; violating rows pass through ---
@dlt.expect('valid_amount', 'amount > 0')
@dlt.expect('valid_status', "status IN ('pending','active','shipped','cancelled')")
@dlt.table(name='orders_silver')
def orders_silver():
    return dlt.read_stream('orders_bronze').select(
        'order_id', 'customer_id', 'amount', 'status', 'order_date'
    )

# --- @dlt.expect_or_drop: violating rows removed; pipeline continues ---
@dlt.expect_or_drop('not_null_order_id', 'order_id IS NOT NULL')
@dlt.expect_or_drop('positive_amount',   'amount > 0')
@dlt.table(name='orders_silver_clean')
def orders_silver_clean():
    return dlt.read_stream('orders_bronze')

# --- @dlt.expect_or_fail: pipeline halts on any violation ---
@dlt.expect_or_fail('no_duplicate_keys',
    'order_id IS NOT NULL')  # combine with upstream dedup for true uniqueness
@dlt.table(name='orders_gold_strict')
def orders_gold_strict():
    return dlt.read('orders_silver_clean')

# --- @dlt.expect_all: multiple rules, warn/track mode ---
@dlt.expect_all({
    'valid_order_id':  'order_id IS NOT NULL',
    'valid_amount':    'amount > 0',
    'valid_date':      'order_date IS NOT NULL',
    'valid_status':    "status IN ('pending','active','shipped','cancelled')"
})
@dlt.table(name='orders_silver_monitored')
def orders_silver_monitored():
    return dlt.read_stream('orders_bronze')

# --- @dlt.expect_all_or_drop: multiple rules, drop violators ---
@dlt.expect_all_or_drop({
    'valid_order_id': 'order_id IS NOT NULL',
    'valid_amount':   'amount > 0'
})
@dlt.table(name='orders_silver_dropped')
def orders_silver_dropped():
    return dlt.read_stream('orders_bronze')

