# Jobs REST API v2.1 — create job with multi-task DAG
import requests, json

HOST  = 'https://<workspace>.azuredatabricks.net'
TOKEN = dbutils.secrets.get('kv', 'databricks-pat')

job_payload = {
  'name': 'medallion_pipeline',
  'max_concurrent_runs': 1,
  'schedule': {
    'quartz_cron_expression': '0 0 2 * * ?',   # daily at 02:00 UTC
    'timezone_id': 'UTC',
    'pause_status': 'UNPAUSED'
  },
  'email_notifications': {
    'on_failure': ['data-eng-oncall@example.com'],
    'no_alert_for_skipped_runs': True
  },
  'tasks': [
    {
      'task_key': 'bronze_ingest',
      'notebook_task': {
        'notebook_path': '/pipelines/bronze/ingest_orders',
        'base_parameters': {'env': 'prod', 'source': 'orders'}
      },
      'job_cluster_key': 'pipeline_cluster'
    },
    {
      'task_key': 'silver_cleanse',
      'depends_on': [{'task_key': 'bronze_ingest'}],
      'run_if': 'ALL_SUCCESS',
      'notebook_task': {'notebook_path': '/pipelines/silver/cleanse_orders'},
      'job_cluster_key': 'pipeline_cluster'
    },
    {
      'task_key': 'gold_aggregate',
      'depends_on': [{'task_key': 'silver_cleanse'}],
      'notebook_task': {'notebook_path': '/pipelines/gold/aggregate_sales'},
      'job_cluster_key': 'pipeline_cluster'
    },
    {
      'task_key': 'notify_on_failure',
      'depends_on': [{'task_key': 'silver_cleanse'}, {'task_key': 'gold_aggregate'}],
      'run_if': 'AT_LEAST_ONE_FAILED',   # conditional branch: runs only on upstream failure
      'notebook_task': {'notebook_path': '/pipelines/utils/failure_alert'}
    }
  ],
  'job_clusters': [
    {
      'job_cluster_key': 'pipeline_cluster',
      'new_cluster': {
        'spark_version': '15.4.x-scala2.12',
        'node_type_id': 'Standard_DS3_v2',
        'autoscale': {'min_workers': 2, 'max_workers': 8}
      }
    }
  ]
}

resp = requests.post(
  f'{HOST}/api/2.1/jobs/create',
  headers={'Authorization': f'Bearer {TOKEN}'},
