# Sizing formulas (Python)
def recommend_cluster(total_data_gb, workload='mixed'):
    if workload == 'join_heavy':
        ram_per_worker = 64   # memory-optimized: Standard_E8ds_v5 / r5d.2xlarge
        vcpu_per_worker = 8
    elif workload == 'compute':
        ram_per_worker = 32   # compute-optimized: Standard_F8s_v2 / c5.2xlarge
        vcpu_per_worker = 8
    else:
        ram_per_worker = 32   # general: Standard_DS4_v2 / m5.2xlarge
        vcpu_per_worker = 8
    workers = max(2, -(-int(total_data_gb * 8 / ram_per_worker) // 1))  # ceil
    shuffle_partitions = workers * vcpu_per_worker * 2
    return workers, shuffle_partitions

